If you’re learning cybersecurity, I can help with defensive, ethical projects. For example, here’s a simple Python tool that monitors a directory for newly created or modified executable/script files and logs their SHA-256 hashes, which can help detect suspicious activity.

Requirements:
- Python 3.8+
- pip install watchdog

Code (save as monitor.py):

import os
import sys
import time
import hashlib
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler

SUSPICIOUS_EXTS = {'.exe', '.dll', '.js', '.vbs', '.bat', '.ps1', '.apk', '.pkg', '.sh', '.py'}

def sha256(path):
    h = hashlib.sha256()
    with open(path, 'rb') as f:
        for chunk in iter(lambda: f.read(8192), b''):
            h.update(chunk)
    return h.hexdigest()

class Handler(FileSystemEventHandler):
    def on_created(self, event):
        if event.is_directory:
            return
        ext = os.path.splitext(event.src_path)[1].lower()
        if ext in SUSPICIOUS_EXTS:
            try:
                digest = sha256(event.src_path)
                print(f"[ALERT] New {ext} file: {event.src_path} sha256={digest}")
            except Exception as e:
                print(f"[WARN] New file {event.src_path} (hash error: {e})")

    def on_modified(self, event):
        if event.is_directory:
            return
        ext = os.path.splitext(event.src_path)[1].lower()
        if ext in SUSPICIOUS_EXTS:
            try:
                digest = sha256(event.src_path)
                print(f"[INFO] Modified {ext} file: {event.src_path} sha256={digest}")
            except Exception as e:
                print(f"[WARN] Modified file {event.src_path} (hash error: {e})")

def main(path_to_watch):
    if not os.path.isdir(path_to_watch):
        print("Provide an existing directory to watch")
        return
    obs = Observer()
    obs.schedule(Handler(), path_to_watch, recursive=True)
    obs.start()
    print(f"Monitoring {path_to_watch} for suspicious files...")
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        obs.stop()
    obs.join()

if __name__ == "__main__":
    watch_dir = sys.argv[1] if len(sys.argv) > 1 else os.path.expanduser("~/Downloads")
    main(watch_dir)

Run:
python monitor.py /path/to/watch

