Here’s a practical example in Python that shows how to store and verify passwords securely with Argon2, add login rate limiting to deter brute-force attempts, and provide password strength feedback.

Dependencies:
- pip install argon2-cffi

Code:

import time
import re
from argon2 import PasswordHasher
from argon2.exceptions import VerifyMismatchError

# Configure Argon2 for secure password hashing
ph = PasswordHasher(
    time_cost=3,           # computational cost
    memory_cost=64 * 1024, # 64 MB
    parallelism=1,
    salt_len=16,
    hash_len=32
)

def hash_password(plain: str) -> str:
    return ph.hash(plain)

def verify_password(stored_hash: str, plain: str):
    try:
        ph.verify(stored_hash, plain)
        # Optional: transparent rehashing if parameters changed
        if ph.check_needs_rehash(stored_hash):
            return True, ph.hash(plain)
        return True, None
    except VerifyMismatchError:
        return False, None

class RateLimiter:
    """
    Simple per-username+IP limiter:
    - max_attempts within window_seconds leads to block_seconds ban
    """
    def __init__(self, max_attempts=5, window_seconds=300, block_seconds=900):
        self.failed = {}       # key -> [timestamps]
        self.blocked_until = {}# key -> unblock timestamp
        self.max_attempts = max_attempts
        self.window_seconds = window_seconds
        self.block_seconds = block_seconds

    def _now(self):
        return time.time()

    def is_blocked(self, key: str) -> bool:
        return self._now() < self.blocked_until.get(key, 0)

    def register_failure(self, key: str):
        now = self._now()
        attempts = [t for t in self.failed.get(key, []) if now - t <= self.window_seconds]
        attempts.append(now)
        self.failed[key] = attempts
        if len(attempts) >= self.max_attempts:
            self.blocked_until[key] = now + self.block_seconds

    def reset(self, key: str):
        self.failed.pop(key, None)
        self.blocked_until.pop(key, None)

# Simple in-memory user store (replace with a database in production)
store = {}

def create_user(username: str, plain_password: str):
    store[username] = {'password_hash': hash_password(plain_password)}

def login(username: str, plain_password: str, limiter: RateLimiter, client_ip: str):
    key = f"{username}:{client_ip}"
    if limiter.is_blocked(key):
        return False, "Too many failed attempts. Try again later."

    user = store.get(username)
    if not user:
        limiter.register_failure(key)
        return False, "Invalid credentials"

    ok, new_hash = verify_password(user['password_hash'], plain_password)
    if ok:
        limiter.reset(key)
        if new_hash:
            user['password_hash'] = new_hash  # transparent rehash on successful login
        return True, "Login successful"
    else:
        limiter.register_failure(key)
        return False, "Invalid credentials"

# Password strength checker
COMMON = {"password", "123456", "qwerty", "letmein", "admin", "welcome"}

def password_score(pw: str) -> int:
    score = 0
    length = len(pw)
    if length >= 12: score += 2
    elif length >= 8: score += 1
    if re.search(r'[A-Z]', pw): score += 1
    if re.search(r'[a-z]', pw): score += 1
    if re.search(r'\d', pw): score += 1
    if re.search(r'[^A-Za-z0-9]', pw): score += 1
    if pw.lower() in COMMON: score -= 3
    return score

def password_advice(pw: str):
    s = password_score(pw)
    advice = []
    if len(pw) < 12: advice.append("Use at least 12 characters.")
    if not re.search(r'[A-Z]', pw): advice.append("Add uppercase letters.")
    if not re.search(r'[a-z]', pw): advice.append("Add lowercase letters.")
    if not re.search(r'\d', pw): advice.append("Include digits.")
    if not re.search(r'[^A-Za-z0-9]', pw): advice.append("Include symbols.")
    if pw.lower() in COMMON: advice.append("Avoid common passwords.")
    return s, advice

# Example usage
if __name__ == "__main__":
    limiter = RateLimiter()
    create_user("alice", "Secur3P@ssw0rd!")
    print(password_advice("Secur3P@ssw0rd!"))

    print(login("alice", "wrong", limiter, "203.0.113.5"))
    print(login("alice", "Secur3P@ssw0rd!", limiter, "203.0.113.5"))

