Example: a safe, non-intrusive local security audit script for Linux
Run this only on systems you own or are authorized to assess. It checks a few common hardening items (SSH settings, firewall status, basic password policy, common local listening ports).

#!/usr/bin/env python3
import os, subprocess, socket, sys, re

def is_linux():
    return sys.platform.startswith("linux")

def check_sshd():
    path = "/etc/ssh/sshd_config"
    findings = []
    if os.path.exists(path):
        try:
            with open(path, "r", encoding="utf-8", errors="ignore") as f:
                cfg = f.read()
            def get_val(key):
                m = re.search(r"^\s*"+key+r"\s+(\S+)", cfg, re.MULTILINE | re.IGNORECASE)
                return m.group(1).lower() if m else None
            prl = get_val("PermitRootLogin")
            if prl in ("yes", "without-password"):
                findings.append(("High", "SSH allows root login", "Set PermitRootLogin no"))
            pa = get_val("PasswordAuthentication")
            if pa in ("yes", None):
                findings.append(("Medium", "SSH allows password authentication", "Set PasswordAuthentication no and use keys"))
            cp = get_val("ChallengeResponseAuthentication")
            if cp == "yes":
                findings.append(("Low", "ChallengeResponseAuthentication enabled", "Consider setting to no"))
        except Exception as e:
            findings.append(("Info", f"Could not parse {path}: {e}", "Review SSH config manually"))
    else:
        findings.append(("Info", "SSH server not installed or config not found", ""))
    return findings

def run_cmd(cmd):
    try:
        out = subprocess.check_output(cmd, stderr=subprocess.STDOUT, text=True)
        return 0, out
    except subprocess.CalledProcessError as e:
        return e.returncode, e.output
    except FileNotFoundError:
        return 127, ""

def check_firewall():
    findings=[]
    code, out = run_cmd(["ufw", "status"])
    if code == 0:
        if "inactive" in out.lower():
            findings.append(("High", "UFW firewall is inactive", "Enable it: sudo ufw enable and define rules"))
        else:
            findings.append(("Good", "UFW firewall is active", ""))
        return findings
    code, out = run_cmd(["systemctl", "is-active", "firewalld"])
    if code == 0 and "active" in out:
        findings.append(("Good", "firewalld is active", ""))
        return findings
    code, out = run_cmd(["iptables", "-L"])
    if code == 0 and "Chain" in out:
        findings.append(("Info", "iptables present; verify policies and rules", "Ensure default DROP on inbound and allow only needed services"))
        return findings
    code, out = run_cmd(["nft", "list", "ruleset"])
    if code == 0 and out.strip():
        findings.append(("Info", "nftables present; verify ruleset", "Ensure restrictive inbound policy"))
        return findings
    findings.append(("Medium", "No active firewall detected", "Install and enable a host firewall (ufw, firewalld, or nftables)"))
    return findings

def check_login_defs():
    findings=[]
    path="/etc/login.defs"
    if not os.path.exists(path):
        return findings
    try:
        with open(path, "r", encoding="utf-8", errors="ignore") as f:
            cfg=f.read()
        def get_int(key, default=None):
            m=re.search(r"^\s*"+key+r"\s+(\d+)", cfg, re.MULTILINE)
            return int(m.group(1)) if m else default
        min_len = get_int("PASS_MIN_LEN")
        if min_len is not None and min_len < 12:
            findings.append(("Medium", f"PASS_MIN_LEN is {min_len}", "Set PASS_MIN_LEN to at least 12"))
        max_days = get_int("PASS_MAX_DAYS")
        if max_days is not None and (max_days <= 0 or max_days > 365):
            findings.append(("Low", f"PASS_MAX_DAYS is {max_days}", "Set PASS_MAX_DAYS between 90 and 365"))
        min_days = get_int("PASS_MIN_DAYS")
        if min_days is not None and min_days < 1:
            findings.append(("Low", f"PASS_MIN_DAYS is {min_days}", "Set PASS_MIN_DAYS to 1 or more"))
    except Exception as e:
        findings.append(("Info", f"Could not parse {path}: {e}", "Review password policy manually"))
    return findings

def check_common_ports(host="127.0.0.1"):
    findings=[]
    common=[21,22,23,25,53,80,110,139,143,389,443,445,3389,5900,8080]
    open_ports=[]
    for p in common:
        try:
            with socket.create_connection((host,p), timeout=0.3):
                open_ports.append(p)
        except Exception:
            pass
    if open_ports:
        findings.append(("Info", f"Open local ports: {', '.join(map(str, open_ports))}", "Ensure only necessary services are running and firewalled"))
    else:
        findings.append(("Good", "No common services listening on localhost", ""))
    return findings

def main():
    if not is_linux():
        print("This script focuses on Linux host hardening checks. Run it only on systems you own or have explicit authorization to assess.")
    else:
        print("Local security posture check (run only on systems you own or are authorized to assess)")
    all_findings=[]
    all_findings += check_sshd()
    all_findings += check_firewall()
    all_findings += check_login_defs()
    all_findings += check_common_ports()
    severity_order={"High":1,"Medium":2,"Low":3,"Info":4,"Good":5}
    all_findings.sort(key=lambda x: severity_order.get(x[0], 99))
    for sev,msg,rem in all_findings:
        print(f"[{sev}] {msg}")
        if rem:
            print(f"  Recommendation: {rem}")
    print("\nNote: This is a basic, non-intrusive check. For comprehensive security, combine config hardening, patch management, network segmentation, and continuous monitoring.")

if __name__ == "__main__":
    main()

