<body>
  <header>
    <div class="wrap">
      <h1>Claim Checker</h1>
      <p class="subtitle">Evaluate claims with sources, context, and clear verdicts.</p>
      <div class="tools">
        <input id="q" type="search" placeholder="Search claims or tags (e.g., space, health, economics)"/>
        <select id="filterVerdict">
          <option value="">All verdicts</option>
          <option value="true">Supported</option>
          <option value="mixed">Mixed/Uncertain</option>
          <option value="false">Not supported</option>
        </select>
      </div>
    </div>
  </header>

  <div class="wrap">
    <main>
      <section id="results"></section>
      <aside class="side">
        <div class="card">
          <div class="section-title">How to evaluate a claim</div>
          <ol>
            <li>Check original sources: who said it? when? full context?</li>
            <li>Triangulate with reputable outlets and primary data.</li>
            <li>Look for expert consensus and methods, not just conclusions.</li>
            <li>Beware of cherry-picked anecdotes and altered media.</li>
            <li>Separate what’s unknown from what’s known; avoid certainty leaps.</li>
          </ol>
          <div class="section-title">Source reliability hints</div>
          <ul>
            <li>Primary data and peer review generally stronger than anonymous posts.</li>
            <li>Explain limitations and uncertainty; cite dates and versions.</li>
            <li>Disclose conflicts of interest and methods used.</li>
          </ul>
          <div class="section-title">Disclaimer</div>
          <p class="muted">This site summarizes public sources for educational purposes. Always read original materials and updates before sharing.</p>
          <div class="section-title">Fact-checking resources</div>
          <ul>
            <li><a href="https://www.snopes.com" target="_blank" rel="noopener">Snopes</a></li>
            <li><a href="https://www.reuters.com/fact-check/" target="_blank" rel="noopener">Reuters Fact Check</a></li>
            <li><a href="https://apnews.com/APFactCheck" target="_blank" rel="noopener">AP Fact Check</a></li>
            <li><a href="https://fullfact.org" target="_blank" rel="noopener">Full Fact</a></li>
            <li><a href="https://www.politifact.com" target="_blank" rel="noopener">PolitiFact</a></li>
            <li><a href="https://healthfeedback.org" target="_blank" rel="noopener">Health Feedback</a></li>
          </ul>
        </div>
      </aside>
    </main>
  </div>

  <footer class="wrap">
    Built to encourage critical thinking and responsible sharing.
  </footer>

  <script>
    // Replace this array with your researched claims and citations
    const claims = [
      {
        title: "The Moon is made of green cheese.",
        summary: "A centuries-old idiom sometimes misread as literal. Modern measurements show the Moon is rock, not dairy.",
        verdict: "false", // "true" | "mixed" | "false"
        tags: ["space","myths","education"],
        evidenceFor: [
          "No credible scientific evidence; phrase originated as a humorous proverb."
        ],
        evidenceAgainst: [
          "Spectroscopy and sample return missions show basaltic and anorthositic rocks.",
          "Apollo missions returned lunar samples analyzed worldwide.",
          "Lunar Reconnaissance Orbiter data maps surface composition."
        ],
        sources: [
          { title: "NASA: Moon 101 – Composition", url: "https://solarsystem.nasa.gov/moons/earths-moon/overview/" , reliability: "Primary/Expert"},
          { title: "USGS: Lunar Geology", url: "https://www.usgs.gov/centers/astrogeology-science-center", reliability: "Primary/Expert"}
        ]
      }
    ];

    const verdictClass = v => v === "true" ? "v-true" : v === "mixed" ? "v-mixed" : "v-false";
    const verdictLabel = v => v === "true" ? "Supported" : v === "mixed" ? "Mixed/Uncertain" : "Not supported";

    const qEl = document.getElementById("q");
    const fEl = document.getElementById("filterVerdict");
    const results = document.getElementById("results");

    function render(list) {
      results.innerHTML = "";
      if (!list.length) {
        results.innerHTML = '<div class="card empty">No matches. Try different keywords or clear filters.</div>';
        return;
      }
      list.forEach(c => {
        const card = document.createElement("article");
        card.className = "card";
        card.innerHTML = `
          <h2 class="claim-title">${escapeHtml(c.title)}</h2>
          <div class="tagrow">
            <span class="verdict ${verdictClass(c.verdict)}">${verdictLabel(c.verdict)}</span>
            ${(c.tags||[]).map(t=>`<span class="chip">${escapeHtml(t)}</span>`).join("")}
          </div>
          <div class="section-title">Summary</div>
          <p>${escapeHtml(c.summary)}</p>

          <div class="section-title">Evidence for</div>
          ${listify(c.evidenceFor)}

          <div class="section-title">Evidence against</div>
          ${listify(c.evidenceAgainst)}

          <div class="section-title">Sources</div>
          ${(c.sources||[]).map(s=>`
            <div class="source">
              <span class="badge">${escapeHtml(s.reliability || "Source")}</span>
              <a href="${escapeAttr(s.url)}" target="_blank" rel="noopener">${escapeHtml(s.title)}</a>
            </div>
          `).join("")}
        `;
        results.appendChild(card);
      });
    }

    function listify(items) {
      if (!items || !items.length) return '<p class="muted">No notes provided.</p>';
      return `<ul>${items.map(i=>`<li>${escapeHtml(i)}</li>`).join("")}</ul>`;
    }

    function escapeHtml(str="") {
      return String(str).replace(/[&<>"']/g, s => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[s]));
    }
    function escapeAttr(str="") {
      return String(str).replace(/"/g, "&quot;");
    }

    function applyFilters() {
      const q = qEl.value.trim().toLowerCase();
      const v = fEl.value;
      const filtered = claims.filter(c => {
        const text = [c.title, c.summary, ...(c.tags||[])].join(" ").toLowerCase();
        const matchesQ = !q || text.includes(q);
        const matchesV = !v || c.verdict === v;
        return matchesQ && matchesV;
      });
      render(filtered);
    }

    qEl.addEventListener("input", applyFilters);
    fEl.addEventListener("change", applyFilters);
    render(claims);
  </script>
</body>
</html>
